import { CCol, CForm, CFormInput, CContainer, CRow, CFormLabel, CButton } from '@coreui/react';
import React, { useState } from 'react';
import TextArea from '../common/TextArea';

const MagazineComponent = () => {
    const [formData, setFormData] = useState({ title: '', article: '', file: null });

    const handleChange = (e) => {
        const { name, value, files } = e.target;

        if (name === 'file') {
            let selectedFile = files[0];
            setFormData({ ...formData, [name]: selectedFile });

            // Convert the file to Base64
            const reader = new FileReader();
            console.log("readerkk:", reader);
            reader.onloadend = () => {

                //Base64 string
                const base64String = reader.result.split(',')[1];
                console.log("Base64String:", base64String);


                // Format it for Binary.createFromBase64
                const binaryData = `Binary.createFromBase64('${base64String}', 0)`;
                console.log("Binary Data:", binaryData);

                // You can now use binaryData as needed
            };
            reader.readAsDataURL(selectedFile); // Read file as a Data URL
        } else {
            setFormData({ ...formData, [name]: value });
        }
    };


    const handleSubmit = (e) => {
        e.preventDefault();
        console.log('FormDataSubmitted:', formData);
    };

    return (
        <CContainer className="d-flex justify-content-center align-items-center" style={{ minHeight: '50vh' }}>
            <CRow className="w-90">
                <CCol md={12}>
                    <CFormLabel htmlFor="formFile">Title<span className="text-danger">*</span></CFormLabel>
                    <CForm>
                        <CFormInput
                            id="exampleFormControlInput1"
                            placeholder="Enter title"
                            name="title"
                            value={formData?.title}
                            onChange={(e) => {handleChange(e)}}
                        />
                    </CForm>
                </CCol>
                <CCol md={12}>
                    <TextArea
                        value={formData?.article}
                        label="Article"
                        required
                        name="article"
                        onChange={(e) => {handleChange(e)}}
                        placeholder="Write your article here"
                    />
                </CCol>
                <CCol md={12}>
                    <div>
                        <CFormInput
                            type="file"
                            size="lg"
                            id="formFileLg"
                            label="Large file input example"
                            name="file"
                            onChange={(e) => {handleChange(e)}} 
                        />
                    </div>
                </CCol>
                <CCol md={12} className="mt-3">
                    <CButton color="primary" onClick={handleSubmit}> Submit </CButton>
                </CCol>
            </CRow>
        </CContainer>
    );
};

export default MagazineComponent;
